const res = $json;
const status = Number(res.statusCode) || 0;
const body = res.body !== undefined ? res.body : res;
let bodyStr = '';
try { bodyStr = JSON.stringify(body || {}).toLowerCase(); } catch (e) { bodyStr = String(body || '').toLowerCase(); }
let errorType = 'none';
let ok = status >= 200 && status < 300;
if (bodyStr.includes('sha1 is already taken')) { errorType = 'sha1_taken'; ok = false; }
else if (bodyStr.includes('execution_error')) { errorType = 'execution_error'; ok = false; }
else if (bodyStr.includes('ref') && (bodyStr.includes('already') || bodyStr.includes('duplicat') || bodyStr.includes('taken'))) { errorType = 'ref_duplicate'; ok = false; }
else if (status === 401) { errorType = 'unauthorized'; ok = false; }
else if (status === 404) { errorType = 'not_found'; ok = false; }
else if (status === 422) { errorType = 'validation'; ok = false; }
else if (status === 503) { errorType = 'unavailable'; ok = false; }
else if (status >= 400) { errorType = 'http_error'; ok = false; }
return { ok, statusCode: status, data: body, errorType };

